void toggle_frames(const unsigned char* frames[2], int dly) {
  for (int i = 0; i < 2; i++) {
    display.clearDisplay();
    display.drawBitmap(0, 0, frames[i], 128, 64, 1);
    display.display();
    delay(dly);
  }
}

void toggle_frames_millis(const unsigned char* frames[2], int dly, int frameNum) {
  unsigned long now = millis();

  if (now - lastFrameTime > dly) {
    lastFrameTime = now;

    display.clearDisplay();
    display.drawBitmap(0, 0, frames[frameIndex], 128, 64, 1);
    display.display();

    frameIndex = (frameIndex + 1) % frameNum;
  }
}

// Make sure the number for frames is atleast three ^-^
void revolve_frames(int sze, const unsigned char* frames[], int dly) {
  for (int i = 0; i < sze; i++) {
    display.clearDisplay();
    display.drawBitmap(0, 0, frames[i], 128, 64, 1);
    display.display();
    delay(700);
  }

  for (int i = sze - 2; i > 0; i--) {
    display.clearDisplay();
    display.drawBitmap(0, 0, frames[i], 128, 64, 1);
    display.display();
    delay(700);
  }
}

void searchAround() {
  for (int i = 0; i < 5; i++) {
    display.clearDisplay();
    display.drawBitmap(0, 0, search_frames[i], 128, 64, 1);
    display.display();
    delay(700);
  }

  for (int i = 3; i > 0; i--) {
    display.clearDisplay();
    display.drawBitmap(0, 0, search_frames[i], 128, 64, 1);
    display.display();
    delay(700);
  }
}

void wifi_loop() {
  // int anim_idx = 0;
  WiFiClient client = server.available();  // listen for incoming clients

  if (client) {                     // if you get a client,
    Serial.println("New Client.");  // print a message out the serial port
    String currentLine = "";        // make a String to hold incoming data from the client
    while (client.connected()) {    // loop while the client's connected
      if (client.available()) {     // if there's bytes to read from the client,
        char c = client.read();     // read a byte, then
        Serial.write(c);            // print it out the serial monitor
        if (c == '\n') {            // if the byte is a newline character

          // if the current line is blank, you got two newline characters in a row.
          // that's the end of the client HTTP request, so send a response:
          if (currentLine.length() == 0) {
            // HTTP headers always start with a response code (e.g. HTTP/1.1 200 OK)
            // and a content-type so the client knows what's coming, then a blank line:
            client.println("HTTP/1.1 200 OK");
            client.println("Content-type:text/html");
            client.println();

            // the content of the HTTP response follows the header:
            // client.print("Click <a href=\"/H\">here</a> to turn the LED on pin 2 on.<br>");
            // client.print("Click <a href=\"/L\">here</a> to turn the LED on pin 2 off.<br>");
            
            client.print("<a href=\"/D\">default</a><br>");
            client.print("<a href=\"/P\">start petting</a><br>");
            client.print("<a href=\"/S\">ask to search for missing sock</a><br>");

            client.print("<p>It was the delay gang</p><br>");

            // The HTTP response ends with another blank line:
            client.println();
            // break out of the while loop:
            break;
          } else {  // if you got a newline, then clear currentLine:
            currentLine = "";
          }
        } else if (c != '\r') {  // if you got anything else but a carriage return character,
          currentLine += c;      // add it to the end of the currentLine
        }

        // Check to see if the client request was "GET /H" or "GET /L":
        // if (currentLine.endsWith("GET /H")) {
        //   digitalWrite(ledPin, HIGH);  // GET /H turns the LED on
        // }
        // if (currentLine.endsWith("GET /L")) {
        //  digitalWrite(ledPin, LOW);  // GET /L turns the LED off
        // }

        
        if (currentLine.endsWith("GET /D")) {
          // toggle_frames(blink_frames, 700);
          // anim_idx = 0;
          // display.clearDisplay();
          // display.drawBitmap(0, 0, open_eyes_bits, 128, 64, 1);
          // display.display();
          currentAnim = 0;
          frameIndex = 0;
        } else if (currentLine.endsWith("GET /P")) {
          // toggle_frames(uwu_frames, 700);
          // anim_idx = 1;
          // display.clearDisplay();
          // display.drawBitmap(0, 0, uwu_1_bits, 128, 64, 1);
          // display.display();
          currentAnim = 1;
          frameIndex = 0;
        } else if (currentLine.endsWith("GET /S")) {
          // revolve_frames(5, search_frames, 700);
          // anim_idx = 2;
          // display.clearDisplay();
          // display.drawBitmap(0, 0, clueless_uwu_1_bits, 128, 64, 1);
          // display.display();
          currentAnim = 2;
          frameIndex = 0;
        }
      }
    }
    // close the connection:
    client.stop();
    Serial.println("Client Disconnected.");

    // return anim_idx;
  }
}



void setup() {
  // put your setup code here, to run once:
  Serial.begin(115200);

  pinMode(TOUCHPIN, INPUT);
  pinMode(SEARCH_BUTTON, INPUT_PULLUP);
  pinMode(DEFAULT_BUTTON, INPUT_PULLUP);

  ledcAttachPin(BUZZERPIN, 0);

  if(!display.begin(0x3C, true)) {
    Serial.println("SH1106 allocation failed");
    for(;;);
  }

  display.clearDisplay();
  wifi_setup();
}

void loop() {
  // put your main code here, to run repeatedly:
  // blink_default();
  // searchAround();
  // uwu();
  // toggle_frames(uwu_clueless_frames, 700);
  // revolve_frames(5, search_frames, 700);
  wifi_loop();

  int touchval = digitalRead(TOUCHPIN);
  // Serial.println(touchval);
  int searchButtonState = digitalRead(SEARCH_BUTTON);
  int defaultButtonState = digitalRead(DEFAULT_BUTTON);

  if (searchButtonState == LOW) {
    // toggle_frames_millis(search_frames, 700, 5);
    currentAnim = 2;
    Serial.println("serach");
  }
  if (defaultButtonState == LOW) {
    // toggle_frames_millis(blink_frames, 700, 2);
    currentAnim = 0;
    Serial.println("default");
  }

  if (touchval == 1) {
    toggle_frames_millis(uwu_frames, 700, 2);
    buzzerSong();
    delay(200);
  } else {
    if (currentAnim == 0) {
      toggle_frames_millis(blink_frames, 700, 2);
    } else if (currentAnim == 1) {
      toggle_frames_millis(uwu_frames, 700, 2);
    } else if (currentAnim == 2) {
      toggle_frames_millis(uwu_clueless_frames, 700, 2);
    }
  }

  // if (curr_anim == 0) {
  //   toggle_frames(blink_frames, 700);
  // } else if (curr_anim == 1) {
  //   toggle_frames(uwu_frames, 700);
  // } else if (curr_anim == 2) {
  //   revolve_frames(5, search_frames, 700);
  // }
}

